glsl3.vert:
  precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
  attribute vec3 a_position;
  attribute vec2 a_uv0;
  attribute vec4 a_color;
  varying vec4 v_color;
  varying vec2 v_uv0;
#if EXTRA_DATA
  attribute vec4 a_ext;
  varying vec4 v_ext;
#else
  varying float v_alpha;
#endif
  varying float v_texture_idx;
  varying float v_percent;
  varying vec2 v_trans_uv;
  void main () {
    vec4 pos = vec4(a_position, 1);
    #if CC_USE_MODEL
    pos = cc_matViewProj * cc_matWorld * pos;
    #else
    pos = cc_matViewProj * pos;
    #endif
    v_uv0 = a_uv0;
    #if EXTRA_DATA
      v_color = a_color;
      v_ext = a_ext;
      v_texture_idx = a_ext.a * 0.1;
    #else
      v_color = a_color;
      v_texture_idx = a_color.a * 0.1;
      v_color.r = a_color.r /255.0;
      v_color.g = a_color.g /255.0;
      v_color.b = a_color.b /255.0;
      v_color.a = 1.0;
    #endif
    gl_Position = pos;
  }

