#endif
#if TEXTURES_LEVEL >= 5
  uniform sampler2D texture14;
  uniform sampler2D texture15;
#endif
  vec4 getTexture(){
    vec4 o;
        if (v_texture_idx < 0.5) {
          o = texture2D(texture0, v_uv0);
        }
        else if (v_texture_idx < 1.5) {
          o = texture2D(texture1, v_uv0);
        }
        else if (v_texture_idx < 2.5) {
          o = texture2D(texture2, v_uv0);
        }
